def validate(books):
    all_ok = True
    for b in books:
        d = len(b["description"])
        issues = []
        if not (125 <= d <= 150): issues.append(f"desc={d}")
        for i, t in enumerate(b["thoughts"]):
            total = len(t["title"]) + len(t["example"])
            if not (600 <= total <= 800):
                issues.append(f"t{i}={total}")
                all_ok = False
        status = ", ".join(issues) if issues else "OK"
        print(f"  {b['id']} {b['title']}: desc={d} {status}")
    print("All OK!" if all_ok else "ISSUES FOUND")
    return all_ok

validate(books)
with open("C:/books/roblox_batch.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False)
print("Saved.")
